147	export function calculateProgress(goal: Goal): number {
148	  const { startValue, targetValue, currentValue } = goal;
149	  if (targetValue === startValue) return 0;
150	  if (targetValue > startValue) {
151	    // Positive direction: e.g. increase running distance
152	    return Math.min(Math.max((currentValue - startValue) / (targetValue - startValue), 0), 1);
153	  }
154	  // Negative direction: e.g. lose weight
155	  return Math.min(Math.max((startValue - currentValue) / (startValue - targetValue), 0), 1);
156	}
